import 'dart:async';
import 'dart:typed_data';

class VoiceCapture {
  const VoiceCapture({
    required this.audio,
    required this.transcript,
    required this.duration,
    required this.confidence,
  });

  final Uint8List audio;
  final String transcript;
  final Duration duration;
  final double confidence;
}

abstract interface class VoiceCaptureService {
  Future<VoiceCapture> capture({required Duration timeout});
}

class VoiceCaptureTimeout implements Exception {
  const VoiceCaptureTimeout();

  @override
  String toString() => 'VoiceCaptureTimeout';
}

/// In-memory capture adapter used by tests and the offline fake-channel mode.
/// Production capture adapters live behind [VoiceCaptureService].
class FakeVoiceCaptureService implements VoiceCaptureService {
  FakeVoiceCaptureService({
    required this.audio,
    required this.transcript,
    required this.duration,
    required this.confidence,
    this.captureLatency = Duration.zero,
  });

  final Uint8List audio;
  final String transcript;
  final Duration duration;
  final double confidence;
  final Duration captureLatency;

  @override
  Future<VoiceCapture> capture({required Duration timeout}) async {
    final completer = Completer<VoiceCapture>();
    final timer = Timer(captureLatency, () {
      if (!completer.isCompleted) {
        completer.complete(
          VoiceCapture(
            audio: audio,
            transcript: transcript,
            duration: duration,
            confidence: confidence,
          ),
        );
      }
    });

    try {
      return await completer.future.timeout(
        timeout,
        onTimeout: () => throw const VoiceCaptureTimeout(),
      );
    } finally {
      timer.cancel();
    }
  }
}

import 'package:navivox/core/protocol/voice_unavailable_reason.dart';

const noSpeechDetectedVoiceCaptureMessage =
    'No speech was detected. Check microphone permission, device speech recognition, or try speaking closer to the mic.';
const deviceSpeechUnavailableVoiceCaptureMessage =
    'Device speech recognition is unavailable. Install or enable device speech recognition, then return to Navivox.';
const microphonePermissionDeniedVoiceCaptureMessage =
    'Microphone permission denied. Grant microphone permission in Android App info, then return to Navivox.';

class DeviceSpeechUnavailable implements Exception {
  const DeviceSpeechUnavailable([this.message = deviceSttUnavailableReason]);

  final String message;

  @override
  String toString() => message;
}

class SpeechToTextCaptureFailure implements Exception {
  const SpeechToTextCaptureFailure(this.cause);

  final Object cause;

  bool get isNoTranscript => isNoTranscriptVoiceCaptureReason('$cause');

  @override
  String toString() => 'SpeechToTextCaptureFailure: $cause';
}

bool isNoTranscriptVoiceCaptureReason(String reason) {
  final normalized = reason.trim().toLowerCase();
  return normalized == 'no transcript' ||
      normalized == 'empty transcript' ||
      normalized.contains('error_no_match') ||
      normalized.contains('error_speech_timeout');
}

abstract interface class TextToSpeechService {
  Future<void> speak(String text);
  Future<void> stop();
}

class FakeTextToSpeechService implements TextToSpeechService {
  final List<String> spoken = [];
  int stopCalls = 0;

  @override
  Future<void> speak(String text) async {
    spoken.add(text);
  }

  @override
  Future<void> stop() async {
    stopCalls += 1;
  }
}

class NavivoxVoiceSettings {
  const NavivoxVoiceSettings({
    this.continuousVoiceEnabled = true,
    this.profileSwitchingEnabled = true,
    this.commandWord = 'navi',
    this.trustedServerIds = const {},
  });

  final bool continuousVoiceEnabled;
  final bool profileSwitchingEnabled;
  final String commandWord;
  final Set<String> trustedServerIds;

  bool isTrusted(String serverId) => trustedServerIds.contains(serverId);

  NavivoxVoiceSettings copyWith({
    bool? continuousVoiceEnabled,
    bool? profileSwitchingEnabled,
    String? commandWord,
    Set<String>? trustedServerIds,
  }) {
    return NavivoxVoiceSettings(
      continuousVoiceEnabled:
          continuousVoiceEnabled ?? this.continuousVoiceEnabled,
      profileSwitchingEnabled:
          profileSwitchingEnabled ?? this.profileSwitchingEnabled,
      commandWord: commandWord ?? this.commandWord,
      trustedServerIds: trustedServerIds ?? this.trustedServerIds,
    );
  }
}

